#!/usr/bin/env node
/**
 * Editor-parity block validator.
 *
 * Walks every patterns/*.php and templates/*.html (and parts/*.html) in the
 * given theme root, runs each PHP pattern through `php` first so translations
 * and our `wp_json_encode()` dynamic-attribute trick are expanded, then feeds
 * the resulting markup through `@wordpress/blocks` parse(). Any block whose
 * `isValid === false` is reported with the same "Generated by save / Retrieved
 * from post body" diff the WP block editor shows. Any block whose pre-fix
 * `validateBlock` failed but the deprecation pipeline rescued (the silent
 * "Updated Block: …" message in the editor) is also reported, because that
 * means we're shipping legacy markup the editor will silently rewrite.
 *
 * Usage: node check-blocks.mjs <theme-root> [<theme-root> ...]
 *   exit 0 = clean
 *   exit 1 = at least one block failed validation
 *   exit 2 = setup error (jsdom / blocks / php missing)
 *
 * WC blocks are registered as no-op placeholders — their JSON-attr round-trip
 * is enforced by the Python anti-pattern gate in `bin/check.py`, not here.
 */

import { readFileSync, readdirSync, statSync, existsSync } from 'node:fs';
import { join, dirname, resolve, relative } from 'node:path';
import { fileURLToPath } from 'node:url';
import { createRequire } from 'node:module';
import { execFileSync } from 'node:child_process';

import { JSDOM, VirtualConsole } from 'jsdom';

// Capture the real stderr writer up front so we can route validator output
// through it even after we silence `console.error`.
const origConsoleError = ( ...args ) => process.stderr.write( args.join( ' ' ) + '\n' );

// jsdom's virtual console fires `jsdomError` for every CSS rule it can't
// parse. `@wordpress/ui` ships modern `@layer` blocks that trip it, but they
// don't affect block save() output at all. Pipe everything else through.
const virtualConsole = new VirtualConsole();
virtualConsole.on( 'jsdomError', ( err ) => {
	if ( err && err.message === 'Could not parse CSS stylesheet' ) return;
	process.stderr.write( `[jsdom] ${ err.message }\n` );
} );

const dom = new JSDOM( '<!DOCTYPE html><html><body></body></html>', {
	url: 'http://localhost/',
	pretendToBeVisual: true,
	virtualConsole,
} );

function defineGlobal( key, value ) {
	try {
		globalThis[ key ] = value;
	} catch {
		Object.defineProperty( globalThis, key, {
			value,
			writable: true,
			configurable: true,
		} );
	}
}

defineGlobal( 'window', dom.window );
defineGlobal( 'document', dom.window.document );
defineGlobal( 'navigator', dom.window.navigator );
defineGlobal( 'HTMLElement', dom.window.HTMLElement );
defineGlobal( 'Element', dom.window.Element );
defineGlobal( 'Node', dom.window.Node );
defineGlobal( 'MutationObserver', dom.window.MutationObserver );
defineGlobal( 'IntersectionObserver', class { observe() {} unobserve() {} disconnect() {} } );
defineGlobal( 'ResizeObserver', class { observe() {} unobserve() {} disconnect() {} } );
defineGlobal( 'getComputedStyle', dom.window.getComputedStyle );
defineGlobal( 'requestAnimationFrame', ( cb ) => setTimeout( cb, 0 ) );
defineGlobal( 'cancelAnimationFrame', ( id ) => clearTimeout( id ) );
defineGlobal( 'requestIdleCallback', ( cb ) =>
	setTimeout( () => cb( { didTimeout: false, timeRemaining: () => 0 } ), 0 )
);
defineGlobal( 'cancelIdleCallback', ( id ) => clearTimeout( id ) );

// CRITICAL: import @wordpress packages via CommonJS, not ESM. Their `build-module`
// ESM build uses `import 'something.json'` without the `with { type: 'json' }`
// attribute that recent Node insists on. The CJS build doesn't have that issue.
const require = createRequire( import.meta.url );
const { parse, getSaveContent, getBlockType, registerBlockType } = require(
	'@wordpress/blocks'
);
const { registerCoreBlocks } = require( '@wordpress/block-library' );

// Capture the editor's "Updated Block" / parse warnings so we can flag silent
// deprecations (legacy markup that auto-upgrades on load).
const updatedBlocks = [];
let currentDeprecationDiff = null;
console.groupCollapsed = ( ...args ) => {
	if ( typeof args[ 0 ] === 'string' && args[ 0 ].startsWith( 'Updated Block' ) ) {
		currentDeprecationDiff = { name: args.slice( 1 ).join( ' ' ), info: [] };
		updatedBlocks.push( currentDeprecationDiff );
	}
};
console.groupEnd = () => {
	currentDeprecationDiff = null;
};
function shortFormat( arg ) {
	if ( typeof arg === 'string' ) return arg;
	if ( arg && typeof arg === 'object' ) {
		// Block objects and full block-type schemas dump megabytes of JSX/icons;
		// just surface the block name so the message stays readable.
		if ( arg.name && typeof arg.name === 'string' ) return arg.name;
		try {
			const s = JSON.stringify( arg );
			return s.length > 240 ? s.slice( 0, 240 ) + '…' : s;
		} catch {
			return '[unserializable]';
		}
	}
	return String( arg );
}

console.info = ( ...args ) => {
	// `console.info` inside an "Updated Block" group dumps the
	// generated-vs-retrieved diff. Capture it so we can surface it.
	if ( currentDeprecationDiff ) {
		currentDeprecationDiff.info.push( args.map( shortFormat ).join( ' ' ) );
	}
};
console.warn = () => {}; // suppress assorted block-library load-time chatter
console.error = () => {}; // editor logs invalid blocks here; we surface them ourselves

registerCoreBlocks();

const WC_BLOCK_NAMES = [
	'woocommerce/product-collection',
	'woocommerce/product-template',
	'woocommerce/product-image',
	'woocommerce/product-price',
	'woocommerce/product-button',
	'woocommerce/product-rating',
	'woocommerce/product-rating-stars',
	'woocommerce/product-rating-counter',
	'woocommerce/product-stock-indicator',
	'woocommerce/product-sku',
	'woocommerce/product-sale-badge',
	'woocommerce/product-meta',
	'woocommerce/product-summary',
	'woocommerce/product-description',
	'woocommerce/product-details',
	'woocommerce/product-reviews',
	'woocommerce/product-results-count',
	'woocommerce/catalog-sorting',
	'woocommerce/breadcrumbs',
	'woocommerce/single-product',
	'woocommerce/store-notices',
	'woocommerce/customer-account',
	'woocommerce/mini-cart',
	'woocommerce/mini-cart-contents',
	'woocommerce/cart',
	'woocommerce/empty-cart-block',
	'woocommerce/filled-cart-block',
	'woocommerce/cart-items-block',
	'woocommerce/cart-totals-block',
	'woocommerce/cart-cross-sells-block',
	'woocommerce/checkout',
	'woocommerce/order-confirmation-status',
	'woocommerce/order-confirmation-summary',
	'woocommerce/order-confirmation-totals',
	'woocommerce/order-confirmation-totals-wrapper',
	'woocommerce/order-confirmation-shipping-address',
	'woocommerce/order-confirmation-billing-address',
	'woocommerce/order-confirmation-downloads',
	'woocommerce/order-confirmation-downloads-wrapper',
	'woocommerce/order-confirmation-additional-information',
	'woocommerce/order-confirmation-additional-fields',
	'woocommerce/order-confirmation-additional-fields-wrapper',
	'woocommerce/product-collection-no-results',
	'woocommerce/product-gallery',
	'woocommerce/product-gallery-large-image',
	'woocommerce/product-gallery-thumbnails',
	'woocommerce/product-gallery-large-image-next-previous',
	'woocommerce/add-to-cart-form',
	'woocommerce/related-products',
	'woocommerce/featured-product',
	'woocommerce/product-search',
	'woocommerce/all-reviews',
];

// Block names we registered as stubs — skip validation for these (they're
// server-rendered, not part of what we're trying to validate here).
const STUB_BLOCK_NAMES = new Set();

for ( const name of WC_BLOCK_NAMES ) {
	STUB_BLOCK_NAMES.add( name );
	if ( getBlockType( name ) ) continue;
	registerBlockType( name, {
		apiVersion: 3,
		title: name,
		category: 'woocommerce',
		attributes: {},
		supports: { html: false, inserter: false },
		save: () => null,
	} );
}

const STUB_CORE_BLOCKS = [
	'core/post-template',
	'core/term-template',
	'core/term-name',
	'core/term-count',
	'core/terms-query',
	'core/terms-list',
];
for ( const name of STUB_CORE_BLOCKS ) {
	STUB_BLOCK_NAMES.add( name );
	if ( getBlockType( name ) ) continue;
	registerBlockType( name, {
		apiVersion: 3,
		title: name,
		category: 'theme',
		attributes: {},
		supports: { html: false, inserter: false },
		save: () => null,
	} );
}

const __dirname = dirname( fileURLToPath( import.meta.url ) );
const PHP_STUB_PATH = join( __dirname, 'php-stub.php' );

const themeRoots = process.argv.slice( 2 ).map( ( p ) => resolve( p ) );
if ( themeRoots.length === 0 ) themeRoots.push( resolve( process.cwd() ) );

for ( const root of themeRoots ) {
	if ( ! existsSync( root ) ) {
		console.error( `Theme root not found: ${ root }` );
		process.exit( 2 );
	}
}

function listFiles( dir, ext ) {
	if ( ! existsSync( dir ) ) return [];
	return readdirSync( dir )
		.map( ( name ) => join( dir, name ) )
		.filter( ( p ) => statSync( p ).isFile() && p.endsWith( ext ) );
}

function renderPattern( filePath ) {
	try {
		return execFileSync( 'php', [ PHP_STUB_PATH, filePath ], {
			encoding: 'utf-8',
			maxBuffer: 16 * 1024 * 1024,
			stdio: [ 'ignore', 'pipe', 'pipe' ],
		} );
	} catch ( err ) {
		origConsoleError( `php failed for ${ filePath }: ${ err.message }` );
		return null;
	}
}

function readTemplate( filePath ) {
	return readFileSync( filePath, 'utf-8' );
}

function flattenBlocks( blocks ) {
	const out = [];
	for ( const b of blocks ) {
		out.push( b );
		if ( b.innerBlocks && b.innerBlocks.length ) {
			out.push( ...flattenBlocks( b.innerBlocks ) );
		}
	}
	return out;
}

let totalBlocks = 0;
let totalFailures = 0;
const failures = [];
const totalUpdatedBefore = updatedBlocks.length;

let scannedFiles = 0;

for ( const themeRoot of themeRoots ) {
	const patterns = listFiles( join( themeRoot, 'patterns' ), '.php' );
	const templates = listFiles( join( themeRoot, 'templates' ), '.html' );
	const parts = listFiles( join( themeRoot, 'parts' ), '.html' );
	const allFiles = [ ...templates, ...parts, ...patterns ];

	if ( allFiles.length === 0 ) {
		origConsoleError( `No patterns or templates found under ${ themeRoot }` );
		continue;
	}

	for ( const filePath of allFiles ) {
		scannedFiles++;
		const beforeUpdated = updatedBlocks.length;
		const content = filePath.endsWith( '.php' )
			? renderPattern( filePath )
			: readTemplate( filePath );
		if ( content === null ) {
			totalFailures++;
			failures.push( {
				file: filePath,
				themeRoot,
				block: '(php parse error)',
				detail: 'Failed to render pattern PHP — see stderr above.',
			} );
			continue;
		}

		let parsed;
		try {
			parsed = parse( content );
		} catch ( err ) {
			totalFailures++;
			failures.push( {
				file: filePath,
				themeRoot,
				block: '(parse error)',
				detail: err.message,
			} );
			continue;
		}

		for ( const block of flattenBlocks( parsed ) ) {
			if ( ! block.name ) continue;
			// Stub blocks (WC and certain core/post-* blocks) are server-rendered;
			// the editor doesn't validate their save markup so neither should we.
			if ( STUB_BLOCK_NAMES.has( block.name ) ) continue;
			totalBlocks++;
			if ( block.isValid !== false ) continue;

			let generated = '';
			try {
				generated = getSaveContent(
					block.name,
					block.attributes,
					block.innerBlocks
				);
			} catch ( err ) {
				generated = `<save() threw: ${ err.message }>`;
			}
			failures.push( {
				file: filePath,
				themeRoot,
				block: block.name,
				generated,
				retrieved: block.originalContent || '',
				validationIssues: block.validationIssues || [],
			} );
			totalFailures++;
		}

		const newUpdates = updatedBlocks.slice( beforeUpdated );
		for ( const u of newUpdates ) {
			failures.push( {
				file: filePath,
				themeRoot,
				block: '(silent deprecation)',
				detail:
					'Block uses a deprecated serialization shape that the editor auto-upgrades on load: ' +
					u.name +
					'. Update the source markup to the current shape so the editor stops rewriting it.' +
					( u.info && u.info.length
						? '\n        ' + u.info.join( '\n        ' )
						: '' ),
			} );
			totalFailures++;
		}
	}
}

if ( failures.length === 0 ) {
	origConsoleError(
		`✓ Validated ${ totalBlocks } blocks across ${ scannedFiles } file(s) — all isValid.`
	);
	process.exit( 0 );
}

origConsoleError( `\n✗ ${ failures.length } block validation issue(s):\n` );
for ( const f of failures ) {
	const rel = relative( f.themeRoot, f.file );
	const themeName = f.themeRoot.split( '/' ).pop();
	origConsoleError( `─── ${ f.block } in ${ themeName }/${ rel }` );
	if ( f.detail ) {
		origConsoleError( `    ${ f.detail }\n` );
		continue;
	}
	if ( f.validationIssues && f.validationIssues.length ) {
		for ( const issue of f.validationIssues ) {
			const args = ( issue.args || [] ).map( shortFormat ).join( ' ' );
			const msg = ( issue.message || issue.code || '' ) + ' ' + args;
			origConsoleError( `    issue: ${ msg.trim() }` );
		}
	}
	origConsoleError( `\n    Generated by save:\n      ${ String( f.generated ).replace( /\n/g, '\n      ' ) }` );
	origConsoleError( `\n    Retrieved from source:\n      ${ String( f.retrieved ).trim().replace( /\n/g, '\n      ' ) }\n` );
}
origConsoleError(
	`\nTotal: ${ totalFailures } issue(s) across ${ totalBlocks } block(s) in ${ scannedFiles } file(s).`
);
process.exit( 1 );
